import sys

input = sys.stdin.read
data = input().split()

N = int(data[0])
A = list(map(int, data[1:1+N]))

if N == 0:
    print("Bob")
    sys.exit()

# Compute rightward_streak: streak when left end at i
rightward_streak = [0] * N
rightward_streak[N-1] = 1
for i in range(N-2, -1, -1):
    if A[i] < A[i+1]:
        rightward_streak[i] = 1 + rightward_streak[i+1]
    else:
        rightward_streak[i] = 1

# Compute leftward_streak: streak when right end at i
leftward_streak = [0] * N
leftward_streak[0] = 1
for i in range(1, N):
    if A[i-1] > A[i]:
        leftward_streak[i] = 1 + leftward_streak[i-1]
    else:
        leftward_streak[i] = 1

left_s = rightward_streak[0]
right_s = leftward_streak[N-1]

if left_s % 2 == 1 or right_s % 2 == 1:
    print("Alice")
else:
    print("Bob")

